import { OpenAI } from 'openai';
import { z } from 'zod';
import { createInstructor } from '@instructor-ai/instructor';

const CodeSuggestionSchema = z.object({
  filePath: z.string().describe('Target file path'),
  codeBlock: z.string().describe('Complete code replacement'),
  testCases: z.array(z.object({
    input: z.string(),
    expectedOutput: z.string()
  })),
  explanation: z.string().describe('Why this fix works')
});

type CodeSuggestion = z.infer<typeof CodeSuggestionSchema>;

const client = createInstructor({
  client: new OpenAI(),
  mode: 'json-schema'
});

