@verify(
    checks=['code-correctness', 'security-vulnerability-scanning'],
    max_retries=3,
    on_failure=on_failure('log-and-retry')
)
def debug_loop(initial_error: str) -> CodeSuggestion:
    client = from_openai(openai.OpenAI())
    return client.chat.completions.create(
        response_model=CodeSuggestion,
        messages=[
            {"role": "system", "content": "Fix iteratively. Previous attempts failed validation."},
            {"role": "user", "content": f"Error: {initial_error}. Provide working fix:"}
